// Allowed algorithms whitelist to prevent algorithm confusion attacks
const ALLOWED_ALGORITHMS = ['HS256'];

function base64UrlEncode(buffer) {
  return buffer.toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

function base64UrlDecode(str) {
  str = str.replace(/-/g, '+').replace(/_/g, '/');
  const padding = 4 - (str.length % 4);
  if (padding !== 4) {
    str += '='.repeat(padding);
  }
  return Buffer.from(str, 'base64');
}

function createSignature(headerB64, payloadB64, secret) {
  const data = `${headerB64}.${payloadB64}`;
  return base64UrlEncode(
    crypto.createHmac('sha256', secret).update(data, 'utf8').digest()
  );
}

function verifyToken(token) {
  if (typeof token !== 'string') {
    throw new Error('Token must be a string');
  }

  const parts = token.split('.');
  if (parts.length !== 3) {
    throw new Error('Invalid token structure');
  }

  const [headerB64, payloadB64, signatureB64] = parts;

  // Decode and validate header
  let header;
  try {
    header = JSON.parse(base64UrlDecode(headerB64).toString('utf8'));
  } catch (e) {
    throw new Error('Invalid token header');
  }

  // Enforce algorithm whitelist to prevent algorithm confusion attacks (e.g., "none", RS256 vs HS256)
  if (!header.alg || !ALLOWED_ALGORITHMS.includes(header.alg)) {
    throw new Error(`Unsupported or disallowed algorithm: ${header.alg}`);
  }

  if (header.typ && header.typ !== 'JWT') {
    throw new Error('Invalid token type');
  }

  // Verify signature using timing-safe comparison
  const expectedSignature = createSignature(headerB64, payloadB64, JWT_SECRET);
  const sigBuffer = Buffer.from(signatureB64, 'utf8');
  const expectedSigBuffer = Buffer.from(expectedSignature, 'utf8');

  if (sigBuffer.length !== expectedSigBuffer.length || !crypto.timingSafeEqual(sigBuffer, expectedSigBuffer)) {
    throw new Error('Invalid token signature');
  }

  // Decode payload
  let payload;
  try {
    payload = JSON.parse(base64UrlDecode(payloadB64).toString('utf8'));
  } catch (e) {
    throw new Error('Invalid token payload');
  }

  // Validate expiration
  const now = Math.floor(Date.now() / 1000);

  if (payload.exp !== undefined) {
    if (typeof payload.exp !== 'number') {
      throw new Error('Invalid exp claim');
    }
    if (now >= payload.exp) {
      throw new Error('Token has expired');
    }
  }

  // Validate not-before
  if (payload.nbf !== undefined) {
    if (typeof payload.nbf !== 'number') {
      throw new Error('Invalid nbf claim');
    }
    if (now < payload.nbf) {
      throw new Error('Token is not yet valid');
    }
  }

  // Validate issued-at is not in the future (with small clock skew tolerance)
  if (payload.iat !== undefined) {
    if (typeof payload.iat !== 'number') {
      throw new Error('Invalid iat claim');
    }
    const CLOCK_SKEW_SECONDS = 30;
    if (payload.iat > now + CLOCK_SKEW_SECONDS) {
      throw new Error('Token issued in the future');
    }
  }

  return payload;
}

function generateToken(payload, expiresInSeconds = 3600) {
  const header = { alg: 'HS256', typ: 'JWT' };

  const now = Math.floor(Date.now() / 1000);
  const fullPayload = {
    ...payload,
    iat: now,
    exp: now + expiresInSeconds,
  };

  const headerB64 = base64UrlEncode(Buffer.from(JSON.stringify(header), 'utf8'));
  const payloadB64 = base64UrlEncode(Buffer.from(JSON.stringify(fullPayload), 'utf8'));
  const signature = createSignature(headerB64, payloadB64, JWT_SECRET);

  return `${headerB64}.${payloadB64}.${signature}`;
}

// JWT verification middleware
function jwtMiddleware(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader) {
    return res.status(401).json({ error: 'Authorization header is required' });
  }

  // Expect "Bearer <token>" format
  const match = authHeader.match(/^Bearer\s+(\S+)$/);
  if (!match) {
    return res.status(401).json({ error: 'Authorization header must use Bearer scheme' });
  }

  const token = match[1];

  // Reject excessively long tokens to prevent DoS
  if (token.length > 8192) {
    return res.status(401).json({ error: 'Token too large' });
  }

  try {
    const payload = verifyToken(token);
    // Attach user info to request — do not attach the raw token
    req.user = {
      id: payload.sub,
      email: payload.email,
      roles: payload.roles || [],
      iat: payload.iat,
      exp: payload.exp,
    };
    next();
  } catch (err) {
    // Log the specific error server-side but return a generic message to the client
    console.error('JWT verification failed:', err.message);
    return res.status(401).json({ error: 'Invalid or expired token' });
  }
}

// Optional: role-based authorization middleware
function requireRole(...roles) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Authentication required' });
    }
    const userRoles = req.user.roles || [];
    const hasRole = roles.some(role => userRoles.includes(role));
    if (!hasRole) {
      return res.status(403).json({ error: 'Insufficient permissions' });
    }
    next();
  };
}

